'use client';

import * as React from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { useProducts } from '@/lib/useProducts';
import { useCategories } from '@/lib/useCategories';
import { AddProductDialog } from '@/components/inventory/add-product-dialog';
import { useT } from '@/components/language-provider';
import { EditProductDialog } from '@/components/inventory/edit-product-dialog';
import { useDashboardAuth } from '@/lib/dashboard-auth-context';

export default function InventoryPage() {
  const { products, loading, error } = useProducts();
  const { categories } = useCategories();
  const { role } = useDashboardAuth();
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editing, setEditing] = React.useState<null | (typeof products)[number]>(
    null
  );
  const [query, setQuery] = React.useState('');
  const t = useT();

  // Helper function to validate and format image URLs
  const getValidImageUrl = (url: string | null | undefined) => {
    if (!url) return '';
    
    // Return valid URLs, data URIs, and Supabase storage URLs as-is
    if (url.startsWith('data:') || url.startsWith('http') || url.startsWith('/') || 
        url.includes('supabase.co/storage')) {
      return url;
    }
    
    // Only treat as Base64 if it looks like valid Base64 and is reasonably long
    if (isValidBase64Image(url)) {
      return `data:image/jpeg;base64,${url}`;
    }
    
    // For other cases, return empty string to trigger fallback
    return '';
  };

  // Helper function to validate Base64 strings
  const isValidBase64Image = (str: string) => {
    // Base64 should be at least 100 characters and contain only valid characters
    if (str.length < 100 || str.includes(' ')) return false;
    
    // Check if string contains only valid Base64 characters
    const base64Regex = /^[A-Za-z0-9+/=]+$/;
    if (!base64Regex.test(str)) return false;
    
    // Additional check: proper length (multiple of 4 for padding)
    return str.length % 4 === 0;
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
        <div>
          <h1 className="text-xl font-semibold tracking-tight md:text-2xl">
            {t('inventoryTitle')}
          </h1>
          <p className="text-sm text-muted-foreground">
            {t('inventorySubtext')}
          </p>
        </div>
        <Button size="sm" onClick={() => setDialogOpen(true)}>
          {t('addProduct')}
        </Button>
      </div>

      <div className="flex items-center gap-2">
        <Input
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          placeholder="Search by product name or barcode..."
          className="max-w-md"
        />
      </div>

      <div className="overflow-hidden rounded-lg border border-border bg-card">
        <div className="max-h-[65vh] overflow-auto">
          <table className="min-w-full border-collapse text-xs">
            <thead className="sticky top-0 bg-background/90 backdrop-blur z-10">
              <tr className="border-b border-border/60 text-[11px] uppercase tracking-wide text-muted-foreground">
                <th className="px-3 py-2 text-left font-medium">ID</th>
                <th className="px-3 py-2 text-left font-medium">Image</th>
                <th className="px-3 py-2 text-left font-medium">Barcode</th>
                <th className="px-3 py-2 text-left font-medium">SKU</th>
                <th className="px-3 py-2 text-left font-medium">Product Name</th>
                <th className="px-3 py-2 text-left font-medium">Category</th>
                <th className="px-3 py-2 text-left font-medium">Variant</th>
                {role === 'admin' && (
                  <th className="px-3 py-2 text-right font-medium">Purchase</th>
                )}
                <th className="px-3 py-2 text-right font-medium">Sale</th>
                <th className="px-3 py-2 text-right font-medium">Stock</th>
                <th className="px-3 py-2 text-right font-medium">Reorder</th>
                <th className="px-3 py-2 text-left font-medium">Remark</th>
                <th className="px-3 py-2 text-right font-medium">Actions</th>
              </tr>
            </thead>
            <tbody>
              {loading && (
                <tr>
                  <td colSpan={role === 'admin' ? 13 : 12} className="px-3 py-6 text-center text-xs text-muted-foreground">
                    Loading products...
                  </td>
                </tr>
              )}
              {!loading && products.length === 0 && (
                <tr>
                  <td colSpan={role === 'admin' ? 13 : 12} className="px-3 py-6 text-center text-xs text-muted-foreground">
                    No products yet. Use &quot;Add product&quot; to create one.
                  </td>
                </tr>
              )}
              {!loading &&
                products
                  .filter((p) => {
                    const q = query.trim().toLowerCase();
                    if (!q) return true;
                    const name = (p.product_name ?? '').toLowerCase();
                    const bc = String(p.barcode ?? '');
                    return name.includes(q) || bc.includes(q);
                  })
                  .map((product) => {
                    const stock = product.stock_quantity ?? 0;
                    const reorder = product.reorder ?? 2;
                    const isLowStock = stock <= reorder;

                    // Barcode .0 cleanup
                    const cleanBarcode = product.barcode ? String(product.barcode).split('.')[0] : '—';

                    return (
                      <tr
                        key={product.id}
                        className={`border-t border-border/40 hover:bg-secondary/40 ${
                          isLowStock ? "bg-destructive/5" : ""
                        }`}
                      >
                        <td className="px-3 py-2 text-muted-foreground">#{product.id}</td>
                        <td className="px-3 py-2">
                          <div className="h-10 w-10 overflow-hidden rounded-md border border-border/70 bg-muted flex items-center justify-center">
                            {product.image_url ? (
                              <img
                                src={getValidImageUrl(product.image_url)}
                                alt={product.product_name ?? 'Product'}
                                className="h-full w-full object-cover"
                                onError={(e) => {
                                  (e.target as HTMLImageElement).src = 'https://placehold.co/100x100?text=No+Image';
                                }}
                              />
                            ) : (
                              <span className="text-[10px] text-muted-foreground uppercase">N/A</span>
                            )}
                          </div>
                        </td>
                        <td className="px-3 py-2 font-mono text-muted-foreground">{cleanBarcode}</td>
                        <td className="px-3 py-2 text-muted-foreground">{product.default_code || '—'}</td>
                        <td className="px-3 py-2 font-medium">{product.product_name || '—'}</td>
                        <td className="px-3 py-2">{product.category || '—'}</td>
                        <td className="px-3 py-2">{product.variant || '—'}</td>
                        {role === 'admin' && (
                          <td className="px-3 py-2 text-right">
                            {product.purchase_price ?? 0} Ks
                          </td>
                        )}
                        <td className="px-3 py-2 text-right font-semibold">
                          {product.sale_price ?? 0} Ks
                        </td>
                        <td className={`px-3 py-2 text-right font-bold ${isLowStock ? "text-destructive" : ""}`}>
                          {stock}
                        </td>
                        <td className="px-3 py-2 text-right text-muted-foreground">{reorder}</td>
                        <td className="px-3 py-2 text-muted-foreground italic">{product.remark || '—'}</td>
                        <td className="px-3 py-2 text-right">
                          <div className="flex justify-end gap-2">
                            <button
                              className="text-primary hover:underline"
                              onClick={() => setEditing(product)}
                            >
                              Edit
                            </button>
                            <button
                              className="text-destructive hover:underline"
                              onClick={async () => {
                                if (window.confirm('Delete this product?')) {
                                  await fetch('/api/delete-product', {
                                    method: 'POST',
                                    headers: { 'Content-Type': 'application/json' },
                                    body: JSON.stringify({ id: product.id }),
                                  });
                                }
                              }}
                            >
                              Delete
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
            </tbody>
          </table>
        </div>
      </div>

      <AddProductDialog open={dialogOpen} onOpenChange={setDialogOpen} role={role} categories={categories} />
      <EditProductDialog
        open={!!editing}
        onOpenChange={(open) => !open && setEditing(null)}
        role={role}
        product={editing}
      />
    </div>
  );
}